import base from '@/utils/base'
import storage from '@/utils/storage'
export const WebsocketMixin = {
	mounted() {
		// this.initWebSocket();
	},
	destroyed: function() {
		// чж╗х╝Ащб╡щЭвчФЯхС╜хСицЬЯхЗ╜цХ░
		// this.websocketOnclose();
	},
	methods: {
		initWebSocket(toId) {
			console.log("------------WebSocketш┐ЮцОецИРхКЯ");
			var userId = storage.get('userid')
			var url = `${base.get().url.replace(/^http/, "ws")}ws?user_id=` + userId + '&to_id=' + toId;
			if (this.websock == null) {
				this.websock = new WebSocket(url);
				this.websock.onopen = this.websocketOnopen;
				this.websock.onerror = this.websocketOnerror;
				this.websock.onmessage = this.websocketOnmessage;
			}

		},
		websocketOnopen: function() {
			console.log("WebSocketш┐ЮцОецИРхКЯ");
		},
		websocketOnerror: function(e) {
			console.log("WebSocketш┐ЮцОехПСчФЯщФЩшпп");
			this.reconnect();
		},
		websocketOnclose: function(e) {
			if (this.websock) {
				try {
					this.websock.close(1000)
				} catch (err) {
					// ignore
				}
				this.websock = null
			}
			console.log('хЕ│щЧнф║Ж')
		},
		websocketOnmessage:function(e) {
			console.log('цФ╢хИ░ф║Ж',e)
		},
		websocketSend(text) {
			try {
				this.websock.send(text);
			} catch (err) {
				console.log("send failed (" + err.code + ")");
			}
		},
		reconnect() {
		},
	}

}
