					<el-form-item label="цКАшГ╜шпжцГЕ" v-if="detailData.xuqiuxiangqing">
						<div v-html="detailData.xuqiuxiangqing" class="ql-snow ql-editor" style="padding:0;max-height:300px;overflow-y:auto;"></div>
					</el-form-item>
