						<img v-if="detailData.fengmian.substring(0,4)=='http'" :src="detailData.fengmian.split(',')[0]" style="max-width:200px;border-radius:6px;">
						<img v-else :src="$base.url+detailData.fengmian.split(',')[0]" style="max-width:200px;border-radius:6px;">
