</template>

<script>
export default {
	data() {
		return {
			searchForm: {
				xuqiubiaoti: '',
				yonghuxingming: '',
				sfsh: 'х╛Ехобца╕',
			},
			dataList: [],
			pageIndex: 1,
			pageSize: 15,
			totalPage: 0,
			loading: false,
			dataListSelections: [],
			auditDialogVisible: false,
			auditDialogTitle: 'хобца╕',
			auditForm: { sfsh: '', shhf: '' },
			auditRules: {
				sfsh: [{ required: true, message: 'шп╖щАЙцЛйхобца╕ч╗УцЮЬ', trigger: 'change' }],
			},
			auditIds: [],
			auditLoading: false,
			detailDialogVisible: false,
			detailData: null,
			previewVisible: false,
			previewImg: '',
		};
	},
	computed: {
		pendingSelections() {
			return this.dataListSelections.filter(item => item.sfsh === 'х╛Ехобца╕');
		}
	},
	created() {
		this.getDataList();
	},
	methods: {
		search() {
			this.pageIndex = 1;
			this.getDataList();
		},
		getDataList() {
			this.loading = true;
			let params = {
				page: this.pageIndex,
				limit: this.pageSize,
				sort: 'id',
				order: 'desc',
				leixing: 'цКАшГ╜',
			};
			if (this.searchForm.xuqiubiaoti) params['xuqiubiaoti'] = '%' + this.searchForm.xuqiubiaoti + '%';
			if (this.searchForm.yonghuxingming) params['yonghuxingming'] = '%' + this.searchForm.yonghuxingming + '%';
			if (this.searchForm.sfsh) params['sfsh'] = this.searchForm.sfsh;
			this.$http({ url: 'jinengxuqiu/page', method: 'get', params }).then(({ data }) => {
				if (data && data.code === 0) {
					this.dataList = data.data.list;
					this.totalPage = data.data.total;
				} else {
					this.dataList = [];
					this.totalPage = 0;
				}
				this.loading = false;
			});
		},
		sizeChangeHandle(val) {
			this.pageSize = val;
			this.pageIndex = 1;
			this.getDataList();
		},
		currentChangeHandle(val) {
			this.pageIndex = val;
			this.getDataList();
		},
		selectionChangeHandler(val) {
			this.dataListSelections = val;
		},
		quickAudit(row, sfsh) {
			const label = sfsh === 'цШп' ? 'щАЪш┐З' : 'цЛТч╗Э';
			this.$confirm(`чбохоЪ${label}уАМ${row.xuqiubiaoti}уАНя╝Я`, 'хобца╕чбошод', {
				confirmButtonText: 'чбохоЪ',
				cancelButtonText: 'хПЦц╢И',
				type: sfsh === 'цШп' ? 'success' : 'warning',
			}).then(() => {
				this.doAudit([row.id], sfsh, '');
			}).catch(() => {});
		},
		singleAudit(row, sfsh) {
			this.auditIds = [row.id];
			this.auditForm.sfsh = sfsh;
			this.auditForm.shhf = '';
			this.auditDialogTitle = 'хобца╕ - ' + row.xuqiubiaoti;
			this.auditDialogVisible = true;
		},
		batchAudit(sfsh) {
			if (this.pendingSelections.length === 0) {
				this.$message.warning('шп╖щАЙцЛйх╛Ехобца╕чЪДшо░х╜Х');
				return;
			}
			this.auditIds = this.pendingSelections.map(item => item.id);
			this.auditForm.sfsh = sfsh;
			this.auditForm.shhf = '';
			this.auditDialogTitle = 'цЙ╣щЗПхобца╕я╝И' + this.auditIds.length + 'цЭбя╝Й';
			this.auditDialogVisible = true;
		},
		resetAudit(row) {
			this.$confirm(`чбохоЪх░ЖуАМ${row.xuqiubiaoti}уАНщЗНч╜оф╕║х╛Ехобца╕я╝Я`, 'щЗНч╜очбошод', {
				confirmButtonText: 'чбохоЪ',
				cancelButtonText: 'хПЦц╢И',
				type: 'warning',
			}).then(() => {
				this.doAudit([row.id], 'х╛Ехобца╕', '');
			}).catch(() => {});
		},
		submitAudit() {
			this.$refs['auditForm'].validate(valid => {
				if (!valid) return;
				this.auditLoading = true;
				this.doAudit(this.auditIds, this.auditForm.sfsh, this.auditForm.shhf || '');
			});
		},
		doAudit(ids, sfsh, shhf) {
			this.$http({
				url: 'jinengxuqiu/shBatch?sfsh=' + encodeURIComponent(sfsh) + '&shhf=' + encodeURIComponent(shhf),
				method: 'post',
				data: ids,
			}).then(({ data }) => {
				this.auditLoading = false;
				if (data && data.code === 0) {
					this.auditDialogVisible = false;
					this.$message.success('цУНф╜ЬцИРхКЯ');
					this.getDataList();
					this.$emit('audit-changed');
				} else {
					this.$message.error(data.msg);
				}
			}).catch(() => {
				this.auditLoading = false;
			});
		},
		viewDetail(row) {
			this.$http({ url: 'jinengxuqiu/info/' + row.id, method: 'get' }).then(({ data }) => {
				if (data && data.code === 0) {
					this.detailData = data.data;
					this.detailDialogVisible = true;
				} else {
					this.$message.error('шО╖хПЦшпжцГЕхд▒ш┤е');
				}
			});
		},
		previewImage(url) {
			this.previewImg = url;
			this.previewVisible = true;
		},
	},
};
</script>
<style lang="scss" scoped>
