import storage from './storage';
import menu from './menu';
/**
 * цШпхРжцЬЙцЭГщЩР
 * @param {*} key
 */
export function isAuth(tableName,key,index=1) {
	let role = storage.get("role");
	if(!role){
		role = 'чобчРЖхСШ';
	}
	let menus = menu.list();
	for(let i=0;i<menus.length;i++){
		if(menus[i].roleName==role){
			for(let j=0;j<menus[i].backMenu.length;j++){
				for(let k=0;k<menus[i].backMenu[j].child.length;k++){
					if(tableName==menus[i].backMenu[j].child[k].tableName){
						let buttons = menus[i].backMenu[j].child[k].buttons
						for(let n in buttons) {
							if(buttons[n] == key) {
								return true
							}
						}
					}
				}
			}
		}
	}
	return false;
}

/**
 *  * шО╖хПЦх╜УхЙНцЧ╢щЧ┤я╝Иyyyy-MM-dd hh:mm:ssя╝Й
 *   */
export function getCurDateTime() {
	let currentTime = new Date(),
	year = currentTime.getFullYear(),
	month = currentTime.getMonth() + 1 < 10 ? '0' + (currentTime.getMonth() + 1) : currentTime.getMonth() + 1,
	day = currentTime.getDate() < 10 ? '0' + currentTime.getDate() : currentTime.getDate(),
	hour = currentTime.getHours(),
	minute = currentTime.getMinutes(),
	second = currentTime.getSeconds();
	return year + "-" + month + "-" + day + " " +hour +":" +minute+":"+second;
}

/**
 *  * шО╖хПЦх╜УхЙНцЧецЬЯя╝Иyyyy-MM-ddя╝Й
 *   */
export function getCurDate() {
	let currentTime = new Date(),
	year = currentTime.getFullYear(),
	month = currentTime.getMonth() + 1 < 10 ? '0' + (currentTime.getMonth() + 1) : currentTime.getMonth() + 1,
	day = currentTime.getDate() < 10 ? '0' + currentTime.getDate() : currentTime.getDate();
	return year + "-" + month + "-" + day;
}

export function getAge(identityCard) {
	var len = (identityCard + "").length;
	if (len == 0) {
		return 0;
	} else {
		if ((len != 15) && (len != 18))//ш║лф╗╜шпБхП╖чаБхПкшГ╜ф╕║15ф╜НцИЦ18ф╜НхЕ╢хоГф╕НхРИц│Х
		{
			return 0;
		}
	}
	var strBirthday = "";
	if (len == 18)//хдДчРЖ18ф╜НчЪДш║лф╗╜шпБхП╖чаБф╗ОхП╖чаБф╕нх╛ЧхИ░чФЯцЧехТМцАзхИлф╗гчаБ
	{
		strBirthday = identityCard.substr(6, 4) + "/" + identityCard.substr(10, 2) + "/" + identityCard.substr(12, 2);
	}
	if (len == 15) {
		strBirthday = "19" + identityCard.substr(6, 2) + "/" + identityCard.substr(8, 2) + "/" + identityCard.substr(10, 2);
	}
	//цЧ╢щЧ┤хнЧчмжф╕▓щЗМя╝Мх┐Ещб╗цШптАЬ/тАЭ
	var birthDate = new Date(strBirthday);
	var nowDateTime = new Date();
	var age = nowDateTime.getFullYear() - birthDate.getFullYear();
	if (nowDateTime.getMonth() < birthDate.getMonth() || (nowDateTime.getMonth() == birthDate.getMonth() && nowDateTime.getDate() < birthDate.getDate())) {
		age--;
	}
	return age;
}
