  
<template>
	<div class="main-content" style="min-height:100%;width:100%;padding:0;background:none;">
		<!-- хИЧшбищб╡ -->
		<template v-if="showFlag ">
			<div class="admin-search">
				<el-button class="btn-primary" v-if="isAuth('jinengfenlei','цЦ░хвЮ')" size="small" icon="el-icon-plus" @click="addOrUpdateHandler()">цЦ░хвЮ</el-button>
				<div class="search-field">
					<span class="field-label">цКАшГ╜хИЖч▒╗</span>
					<el-input v-model="searchForm.jinengfenlei" placeholder="цРЬч┤вцКАшГ╜хИЖч▒╗..." @keydown.enter="search()" clearable size="small"></el-input>
				</div>
				<div class="search-actions">
					<el-button class="btn-primary" size="small" icon="el-icon-search" @click="search()">цЯешпв</el-button>
					<el-button class="btn-plain" size="small" icon="el-icon-refresh" @click="searchForm={ key: '' }; search()">щЗНч╜о</el-button>
				</div>
			</div>
			<div class="admin-table-wrap">
				<el-table class="tables"
					:stripe='false'
					:border='false'
					v-if="isAuth('jinengfenlei','цЯечЬЛ')"
					:data="dataList"
					v-loading="dataListLoading"
					@selection-change="selectionChangeHandler">
					<el-table-column type="selection" align="center" width="50"></el-table-column>
				<el-table-column :sortable='true' label="х║ПхП╖" type="index" align="center" />
				<el-table-column :sortable='true' prop="jinengfenlei" label="цКАшГ╜хИЖч▒╗" align="center" />
				<el-table-column label="цУНф╜Ь" align="center">
					<template #default="scope">
						<el-button v-if="isAuth('jinengfenlei','ф┐оцФ╣')" type="warning" plain size="small" @click="handleEdit(scope.row)">ф┐оцФ╣</el-button>
						<el-button v-if="isAuth('jinengfenlei','хИащЩд')" type="danger" plain size="small" @click="deleteHandler(scope.row.id)">хИащЩд</el-button>
					</template>
				</el-table-column>
				</el-table>
			</div>
			<div class="admin-pagination">
				<el-pagination
					@size-change="sizeChangeHandle"
					@current-change="currentChangeHandle"
					:current-page="pageIndex"
					background

					:page-size="pageSize"
					:layout="layouts.join()"
					:total="totalPage"
					prev-text="< "
					next-text="> "
					:hide-on-single-page="false"
				></el-pagination>
			</div>
		</template>
		<!-- ц╖╗хКа/ф┐оцФ╣щб╡щЭв  х░ЖчИ╢ч╗Дф╗╢чЪДsearchцЦ╣ц│Хф╝ащАТч╗ЩхнРч╗Дф╗╢-->
		<add-or-update v-if="addOrUpdateFlag" :parent="this" ref="addOrUpdate"></add-or-update>





	</div>
</template>

<script>
	import * as echarts from 'echarts'
	import chinaJson from "@/components/echarts/china.json";
	import axios from 'axios';
	import AddOrUpdate from "./add-or-update.vue";
	export default {
		components: {
			AddOrUpdate},
		data() {
			return {
				indexQueryCondition: '',
				searchForm: {
					key: ""
				},
				form:{},
				dataList: [],
				pageIndex: 1,
				pageSize: 15,
				totalPage: 0,
				dataListLoading: false,
				dataListSelections: [],
				showFlag: true,
				addOrUpdateFlag:false,
				layouts: ["total","prev","pager","next","jumper"],
			};
		},
		created() {
			if(this.statType) {
				return false
			}
			this.init();
			this.getDataList();
		},
		mounted() {
		},
		watch: {
		},
		computed: {
			tablename(){
				return this.$storage.get('sessionTable')
			},
			role(){
				return this.$storage.get('role')
			},
			statType() {
				return this.$route.path.endsWith('stat')
			}
		},
		methods: {
			queryChange(arr){
				for(let x in arr) {
					if(arr[x] == this.role) {
						return true
					}
				}
				return false
			},
		init () {
		},
			search() {
				this.pageIndex = 1;
				this.getDataList();
			},

			// шО╖хПЦцХ░цНохИЧшби
			getDataList() {
				this.dataListLoading = true;
				let params = {
					page: this.pageIndex,
					limit: this.pageSize,
					sort: 'id',
					order: 'desc',
				}
				if(this.searchForm.jinengfenlei!='' && this.searchForm.jinengfenlei!=undefined){
					params['jinengfenlei'] = '%' + this.searchForm.jinengfenlei + '%'
				}
				let user = JSON.parse(this.$storage.getObj('userForm'))
				this.$http({
					url: "jinengfenlei/page",
					method: "get",
					params: params
				}).then(({ data }) => {
					if (data && data.code === 0) {
						this.dataList = data.data.list;
						this.totalPage = data.data.total;
					} else {
						this.dataList = [];
						this.totalPage = 0;
					}
					this.dataListLoading = false;
				});
			},
			// цпПщб╡цХ░
			sizeChangeHandle(val) {
				this.pageSize = val;
				this.pageIndex = 1;
				this.getDataList();
			},
			// х╜УхЙНщб╡
			currentChangeHandle(val) {
				this.pageIndex = val;
				this.getDataList();
			},
			// хдЪщАЙ
			selectionChangeHandler(val) {
				this.dataListSelections = val;
			},
		handleEdit(row) {
			this.$http({
				url: "jinengxuqiu/page",
				method: "get",
				params: { page: 1, limit: 1, jinengfenlei: row.jinengfenlei }
			}).then(({ data }) => {
				if (data && data.code === 0 && data.data.total > 0) {
					this.$message({ type: 'warning', message: 'шпехИЖч▒╗ф╕Лх╖▓цЬЙцКАшГ╜цХ░цНоя╝Мф╕НхЕБшо╕ф┐оцФ╣я╝Б', duration: 2000 });
				} else {
					this.addOrUpdateHandler(row.id);
				}
			}).catch(() => {
				this.addOrUpdateHandler(row.id);
			});
		},
		// ц╖╗хКа/ф┐оцФ╣
		addOrUpdateHandler(id,type) {
				this.showFlag = false;
				this.addOrUpdateFlag = true;
				this.crossAddOrUpdateFlag = false;
				if(type!='info'&&type!='msg'){
					type = 'else';
				}
				this.$nextTick(() => {
					this.$refs.addOrUpdate.init(id,type );
				});
			},
			// хИащЩд
			async deleteHandler(id ) {
				var ids = id? [Number(id)]: this.dataListSelections.map(item => {
					return Number(item.id);
				});
				await this.$confirm(`чбохоЪш┐ЫшбМ[${id ? "хИащЩд" : "цЙ╣щЗПхИащЩд"}]цУНф╜Ь?`, "цПРчд║", {
					confirmButtonText: "чбохоЪ",
					cancelButtonText: "хПЦц╢И",
					type: "warning"
				}).then(async () => {
					await this.$http({
						url: "jinengfenlei/delete",
						method: "post",
						data: ids
					}).then(async ({ data }) => {
						if (data && data.code === 0) {
							this.$message({
								message: "цУНф╜ЬцИРхКЯ",
								type: "success",
								duration: 1500,
								onClose: () => {
									this.search();
								}
							});
			
						} else {
							this.$message.error(data.msg);
						}
					});
				});
			},


		}

	};
</script>
