  
<template>
	<div class="main-content" style="min-height:100%;width:100%;padding:0;background:none;">
		<!-- хИЧшбищб╡ -->
		<template v-if="showFlag ">
			<div class="admin-search">
				<div class="search-actions">
					<el-button class="btn-primary" size="small" type="primary" @click="search()"><template #icon><Search /></template>цЯешпв</el-button>
					<el-button class="btn-plain" size="small" @click="refreshClick()"><template #icon><RefreshRight /></template>щЗНч╜о</el-button>
				</div>
			</div>
			<div class="admin-actions">
				<div class="action-left">
					<el-button class="btn-primary" v-if="isAuth('users','цЦ░хвЮ')" size="small" @click="addOrUpdateHandler()"><template #icon><Plus /></template>цЦ░хвЮ</el-button>
					<el-button class="btn-danger" v-if="isAuth('users','хИащЩд')" :disabled="dataListSelections.length?false:true" size="small" @click="deleteHandler()"><template #icon><Delete /></template>хИащЩд</el-button>
				</div>
			</div>
			<div class="admin-table-wrap">
				<el-table class="tables"
					:stripe='false'
					:border='false'
					v-if="isAuth('users','цЯечЬЛ')"
					:data="dataList"
					v-loading="dataListLoading"
					@selection-change="selectionChangeHandler">
					<el-table-column :resizable='true' type="selection" align="center" width="50"></el-table-column>
					<el-table-column :resizable='true' :sortable='true' label="х║ПхП╖" type="index" width="50" />
					<el-table-column :resizable='true' :sortable='true'
												prop="username"
						label="чФицИ╖хРН">
						<template #default="scope">
							{{scope.row.username}}
						</template>
					</el-table-column>
					<el-table-column :resizable='true' :sortable='true'
												prop="role"
						label="шзТшЙ▓">
						<template #default="scope">
							{{scope.row.role}}
						</template>
					</el-table-column>
					<el-table-column  :resizable='true' prop="image" width="200" label="хд┤хГП">
						<template #default="scope">
							<div v-if="scope.row.image">
								<img v-if="scope.row.image.substring(0,4)=='http'&&scope.row.image.split(',w').length>1" :src="scope.row.image" width="100" height="100" style="object-fit: cover" @click="imgPreView(scope.row.image)">
								<img v-else-if="scope.row.image.substring(0,4)=='http'" :src="scope.row.image.split(',')[0]" width="100" height="100" style="object-fit: cover" @click="imgPreView(scope.row.image.split(',')[0])">
								<img v-else :src="$base.url+scope.row.image.split(',')[0]" width="100" height="100" style="object-fit: cover" @click="imgPreView($base.url+scope.row.image.split(',')[0])">
							</div>
							<div v-else>цЧахЫ╛чЙЗ</div>
						</template>
					</el-table-column>
					<el-table-column width="300" label="цУНф╜Ь">
						<template #default="scope">
							<el-button v-if=" isAuth('users','цЯечЬЛ')" type="success" plain size="small" @click="addOrUpdateHandler(scope.row.id,'info')">цЯечЬЛ</el-button>
							<el-button v-if=" isAuth('users','ф┐оцФ╣') " type="warning" plain size="small" @click="addOrUpdateHandler(scope.row.id)">ф┐оцФ╣</el-button>
							<el-button v-if="isAuth('users','хИащЩд')" type="danger" plain size="small" @click="deleteHandler(scope.row.id)">хИащЩд</el-button>
						</template>
					</el-table-column>
				</el-table>
			</div>
			<div class="admin-pagination">
				<el-pagination
					@size-change="sizeChangeHandle"
					@current-change="currentChangeHandle"
					:current-page="pageIndex"
					background

					:page-size="pageSize"
					:layout="layouts.join()"
					:total="totalPage"
					prev-text="< "
					next-text="> "
					:hide-on-single-page="false"
				></el-pagination>
			</div>
		</template>
		<!-- ц╖╗хКа/ф┐оцФ╣щб╡щЭв  х░ЖчИ╢ч╗Дф╗╢чЪДsearchцЦ╣ц│Хф╝ащАТч╗ЩхнРч╗Дф╗╢-->
		<add-or-update v-if="addOrUpdateFlag" :parent="this" ref="addOrUpdate"></add-or-update>





		<el-dialog title="щвДшзИхЫ╛" :visible.sync="previewVisible" width="480px" :close-on-click-modal="false">
			<img :src="previewImg" alt="" style="width: 100%;">
		</el-dialog>
	</div>
</template>

<script>
	import AddOrUpdate from "./add-or-update.vue";
	export default {
		data() {
			return {
				indexQueryCondition: '',
				searchForm: {
					key: ""
				},
				form:{},
				dataList: [],
				pageIndex: 1,
				pageSize: 15,
				totalPage: 0,
				dataListLoading: false,
				dataListSelections: [],
				showFlag: true,
				addOrUpdateFlag:false,
				layouts: ["total","prev","pager","next","jumper"],
				previewImg: '',
				previewVisible: false,
			};
		},
		created() {
			if(this.statType) {
				return false
			}
			this.init();
			this.getDataList();
		},
		mounted() {
		},
		watch: {
		},
		computed: {
			tablename(){
				return this.$storage.get('sessionTable')
			},
			role(){
				return this.$storage.get('role')
			},
		},
		components: {
			AddOrUpdate},
		methods: {
			refreshClick(){
				this.searchForm = {}
				this.search()
			},
			queryChange(arr){
				for(let x in arr) {
					if(arr[x] == this.role) {
						return true
					}
				}
				return false
			},
			imgPreView(url){
				this.previewImg = url
				this.previewVisible = true
				
			},
			init () {
			},
			search() {
				this.pageIndex = 1;
				this.getDataList();
			},

			// шО╖хПЦцХ░цНохИЧшби
			getDataList() {
				this.dataListLoading = true;
				let params = {
					page: this.pageIndex,
					limit: this.pageSize,
					sort: 'id',
					order: 'desc',
				}
				let user = JSON.parse(this.$storage.getObj('userForm'))
				this.$http({
					url: "users/page",
					method: "get",
					params: params
				}).then(({ data }) => {
					if (data && data.code === 0) {
						this.dataList = data.data.list;
						this.totalPage = data.data.total;
					} else {
						this.dataList = [];
						this.totalPage = 0;
					}
					this.dataListLoading = false;
				});
			},
			// цпПщб╡цХ░
			sizeChangeHandle(val) {
				this.pageSize = val;
				this.pageIndex = 1;
				this.getDataList();
			},
			// х╜УхЙНщб╡
			currentChangeHandle(val) {
				this.pageIndex = val;
				this.getDataList();
			},
			// хдЪщАЙ
			selectionChangeHandler(val) {
				this.dataListSelections = val;
			},
			// ц╖╗хКа/ф┐оцФ╣
			addOrUpdateHandler(id,type) {
				this.showFlag = false;
				this.addOrUpdateFlag = true;
				this.crossAddOrUpdateFlag = false;
				if(type!='info'&&type!='msg'){
					type = 'else';
				}
				this.$nextTick(() => {
					this.$refs.addOrUpdate.init(id,type );
				});
			},
			// цЯечЬЛшпДшо║
			disscussListHandler(id,type) {
				this.$router.push({path:'/discussusers',query:{refid:id}});
			},
			// хИащЩд
			async deleteHandler(id ) {
				var ids = id? [Number(id)]: this.dataListSelections.map(item => {
					return Number(item.id);
				});
				await this.$confirm(`чбохоЪш┐ЫшбМ[${id ? "хИащЩд" : "цЙ╣щЗПхИащЩд"}]цУНф╜Ь?`, "цПРчд║", {
					confirmButtonText: "чбохоЪ",
					cancelButtonText: "хПЦц╢И",
					type: "warning"
				}).then(async () => {
					await this.$http({
						url: "users/delete",
						method: "post",
						data: ids
					}).then(async ({ data }) => {
						if (data && data.code === 0) {
							this.$message({
								message: "цУНф╜ЬцИРхКЯ",
								type: "success",
								duration: 1500,
								onClose: () => {
									this.search();
								}
							});
			
						} else {
							this.$message.error(data.msg);
						}
					});
				});
			},


		}

	};
</script>
