			getChatList() {
				this.$http.get('chatmessage/mlist', {
					params: {
						page: 1,
						limit: 1000,
						uid: this.myid,
						fid: this.nowfid
					}
				}).then(res => {
					if (res.data && res.data.code == 0) {
						this.chatList = this.formatMessages(res.data.data.list)
						let div = document.getElementsByClassName('chat-content')[0]
						setTimeout(() => {
							if (div)
								div.scrollTop = div.scrollHeight
						}, 0)
					}
				})
			},
			formatMessages(messages) {
				let lastTime = null;
				messages.forEach((message, index) => {
					const currentTime = new Date(message.addtime).getTime();
					if (lastTime !== null) {
						const timeDiff = (currentTime - lastTime) / 1000 / 60; // ш╜мцНвф╕║хИЖщТЯ
						if (timeDiff < 3) {
							message.addtime = ''; // хжВцЮЬх░Пф║О3хИЖщТЯя╝Мф╕НцШ╛чд║цЧ╢щЧ┤
						}
					}
					lastTime = currentTime;
				});
				return messages;
			},
			timeFormat(time) {
				const Time = timeMethod.getTime(time).split("T");
				//х╜УхЙНц╢ИцБпцЧецЬЯх▒Юф║ОхСи
				const week = timeMethod.getDateToWeek(time);
				//х╜УхЙНцЧецЬЯ0цЧ╢
				const nti = timeMethod.setTimeZero(timeMethod.getNowTime());
				//ц╢ИцБпцЧецЬЯх╜Ухдй0цЧ╢
				const mnti = timeMethod.setTimeZero(timeMethod.getTime(time));
				//шобчоЧцЧецЬЯх╖охА╝
				const diffDate = timeMethod.calculateTime(nti, mnti);
				//цЬмхСиф╕АцЧецЬЯ0цЧ╢ я╝ИхРОщЭв+1цШпхО╗щЩдх╜УхдйцЧ╢щЧ┤я╝Й
				const fwnti = timeMethod.setTimeZero(timeMethod.countDateStr(-timeMethod.getDateToWeek(timeMethod
					.getNowTime()).weekID + 1));
				//шобчоЧхСицЧецЬЯх╖охА╝
				const diffWeek = timeMethod.calculateTime(mnti, fwnti);

				if (diffDate === 0) { //ц╢ИцБпхПСщАБцЧецЬЯхЗПхО╗х╜УхдйцЧецЬЯхжВцЮЬчнЙф║О0хИЩцШпх╜УхдйцЧ╢щЧ┤
					return Time[1].slice(0, 5);
				} else if (diffDate < 172800000) { //х╜УхЙНцЧецЬЯхЗПхО╗ц╢ИцБпхПСщАБцЧецЬЯх░Пф║О2хдйя╝И172800000msя╝ЙхИЩцШпцШихдй-  ф╕АхдйцЬАхдзх╖охА╝хЙНхдйхЗМцЩи00:00:00хИ░ф╗КхдйцЩЪф╕К23:59:59
					return "цШихдй " + Time[1].slice(0, 5);
				} else if (diffWeek >= 0) { //ц╢ИцБпцЧецЬЯхЗПхО╗цЬмхСиф╕АцЧецЬЯхдзф║О0хИЩцШпцЬмхСи
					return week.weekName;
				} else { //хЕ╢ф╗ЦцЧ╢щЧ┤хИЩцШпцЧецЬЯ
					return Time[0].slice(5, 10);
				}
			},
