			// х╝АхзЛх╜ХщЯ│
			async startRecord() {
				if (this.isRecording) return
				
				try {
					// шп╖ц▒Вщ║жхЕЛщгОцЭГщЩР
					this.audioStream = await navigator.mediaDevices.getUserMedia({ audio: true })
					
					// цгАцЯец╡ПшзИхЩицШпхРжцФпцМБ MediaRecorder
					if (!window.MediaRecorder) {
						this.$message.error('цВичЪДц╡ПшзИхЩиф╕НцФпцМБх╜ХщЯ│хКЯшГ╜')
						return
					}
					
					// шО╖хПЦцФпцМБчЪД MIME ч▒╗хЮЛ
					let mimeType = 'audio/webm'
					if (!MediaRecorder.isTypeSupported('audio/webm')) {
						if (MediaRecorder.isTypeSupported('audio/mp4')) {
							mimeType = 'audio/mp4'
						} else if (MediaRecorder.isTypeSupported('audio/ogg')) {
							mimeType = 'audio/ogg'
						} else {
							mimeType = '' // ф╜┐чФиц╡ПшзИхЩищ╗Шшодца╝х╝П
						}
					}
					
					// хИЭхзЛхМЦх╜ХщЯ│хЩи
					const options = mimeType ? { mimeType: mimeType } : {}
					this.mediaRecorder = new MediaRecorder(this.audioStream, options)
					this.audioChunks = []
					
					// чЫСхРмцХ░цНохПпчФиф║Лф╗╢я╝ИцпП100msцФ╢щЫЖф╕АцмбцХ░цНоя╝Й
					this.mediaRecorder.ondataavailable = (event) => {
						if (event.data && event.data.size > 0) {
							this.audioChunks.push(event.data)
						}
					}
					
					// чЫСхРмх╜ХщЯ│хБЬцнвф║Лф╗╢
					this.mediaRecorder.onstop = () => {
						// хБЬцнвцЙАцЬЙщЯ│щвСш╜ищБУ
						if (this.audioStream) {
							this.audioStream.getTracks().forEach(track => track.stop())
							this.audioStream = null
						}
					}
					
					// чЫСхРмщФЩшппф║Лф╗╢
					this.mediaRecorder.onerror = (event) => {
						console.error('х╜ХщЯ│щФЩшпп:', event.error)
						this.$message.error('х╜ХщЯ│ш┐ЗчиЛф╕нхПСчФЯщФЩшпп')
						this.stopRecord()
					}
					
					// х╝АхзЛх╜ХщЯ│я╝МцпП100msцФ╢щЫЖф╕АцмбцХ░цНо
					this.mediaRecorder.start(100)
					this.isRecording = true
					this.recordDuration = 0
					
					// х╝АхзЛшобцЧ╢
					this.recordTimer = setInterval(() => {
						this.recordDuration++
						// цЬАщХ┐х╜ХщЯ│60чзТ
						if (this.recordDuration >= 60) {
							this.stopRecord()
							this.$message.info('х╜ХщЯ│х╖▓ш╛╛хИ░цЬАхдзцЧ╢щХ┐я╝Мх╖▓шЗкхКихБЬцнв')
						}
					}, 1000)
					
				} catch (error) {
					console.error('цЧац│Хшо┐щЧощ║жхЕЛщгО:', error)
					this.isRecording = false
					if (error.name === 'NotAllowedError' || error.name === 'PermissionDeniedError') {
						this.$message.error('щ║жхЕЛщгОцЭГщЩРшвлцЛТч╗Эя╝Мшп╖хЬиц╡ПшзИхЩишо╛ч╜оф╕нхЕБшо╕шо┐щЧощ║жхЕЛщгО')
					} else if (error.name === 'NotFoundError' || error.name === 'DevicesNotFoundError') {
						this.$message.error('цЬкцгАц╡ЛхИ░щ║жхЕЛщгОшо╛хдЗ')
					} else {
						this.$message.error('цЧац│Хшо┐щЧощ║жхЕЛщгОя╝Мшп╖цгАцЯецЭГщЩРшо╛ч╜о')
					}
				}
			},
			// хБЬцнвх╜ХщЯ│
			stopRecord() {
				if (!this.isRecording) return
				
				// ц╕ЕщЩдшобцЧ╢хЩи
				if (this.recordTimer) {
					clearInterval(this.recordTimer)
					this.recordTimer = null
				}
				
				// хБЬцнвх╜ХщЯ│
				if (this.mediaRecorder && this.mediaRecorder.state !== 'inactive') {
					try {
						this.mediaRecorder.stop()
					} catch (e) {
						console.error('хБЬцнвх╜ХщЯ│хд▒ш┤е:', e)
					}
				}
				
				this.isRecording = false
				
				// хжВцЮЬх╜ХщЯ│цЧ╢щХ┐хдкчЯня╝Мф╕НхПСщАБ
				if (this.recordDuration < 1) {
					this.$message.warning('х╜ХщЯ│цЧ╢щЧ┤хдкчЯня╝Мшп╖шЗ│х░Сх╜ХщЯ│1чзТ')
					this.recordDuration = 0
					this.audioChunks = []
					return
				}
				
				// чнЙх╛Ех╜ХщЯ│цХ░цНоцФ╢щЫЖхоМцИР
				setTimeout(() => {
					this.uploadAudio()
				}, 200)
			},
			// ф╕Кф╝ах╜ХщЯ│
			uploadAudio() {
				if (this.audioChunks.length === 0) {
					this.$message.error('х╜ХщЯ│цХ░цНоф╕║чй║')
					return
				}
				
				// чбохоЪцЦЗф╗╢цЙйх▒ХхРН
				let fileExtension = 'webm'
				let mimeType = 'audio/webm'
				if (this.mediaRecorder && this.mediaRecorder.mimeType) {
					mimeType = this.mediaRecorder.mimeType
					if (mimeType.includes('mp4')) {
						fileExtension = 'mp4'
					} else if (mimeType.includes('ogg')) {
						fileExtension = 'ogg'
					} else if (mimeType.includes('wav')) {
						fileExtension = 'wav'
					}
				}
				
				// хРИх╣╢щЯ│щвСцХ░цНо
				const audioBlob = new Blob(this.audioChunks, { type: mimeType })
				
				// цгАцЯецЦЗф╗╢хдзх░Пя╝ИщЩРхИ╢ф╕║10MBя╝Й
				if (audioBlob.size > 10 * 1024 * 1024) {
					this.$message.error('х╜ХщЯ│цЦЗф╗╢ш┐Зхдзя╝Мшп╖ч╝йчЯнх╜ХщЯ│цЧ╢щЧ┤')
					this.audioChunks = []
					this.recordDuration = 0
					return
				}
				
				// хИЫх╗║FormDataф╕Кф╝а
				const formData = new FormData()
				formData.append('file', audioBlob, `voice_${Date.now()}.${fileExtension}`)
				
				// цШ╛чд║ф╕Кф╝ацПРчд║
				const loading = this.$loading({
					lock: true,
					text: 'цнгхЬиф╕Кф╝ашпнщЯ│...',
					background: 'rgba(0, 0, 0, 0.7)'
				})
				
				// ф╕Кф╝ацЦЗф╗╢
				this.$http.post(this.uploadUrl, formData, {
					headers: {
						'Content-Type': 'multipart/form-data'
					}
				}).then(res => {
					loading.close()
					if (res.data && res.data.code == 0) {
						// ф╕Кф╝ацИРхКЯя╝МхПСщАБшпнщЯ│ц╢ИцБп
						this.addChat('upload/' + res.data.file, 5)
						this.$message.success('шпнщЯ│хПСщАБцИРхКЯ')
					} else {
						this.$message.error(res.data.msg || 'ф╕Кф╝ахд▒ш┤е')
					}
				}).catch(error => {
					loading.close()
					console.error('ф╕Кф╝ахд▒ш┤е:', error)
					this.$message.error('шпнщЯ│ф╕Кф╝ахд▒ш┤ея╝Мшп╖щЗНшпХ')
				}).finally(() => {
					// щЗНч╜очК╢цАБ
					this.audioChunks = []
					this.recordDuration = 0
					this.mediaRecorder = null
				})
			},
