  
<template>
	<div class="main-content" style="min-height:100%;width:100%;padding:0;background:none;">
		<!-- хИЧшбищб╡ -->
		<template v-if="showFlag ">
			<div class="admin-search">
				<div class="search-field">
					<el-button class="btn-plain" size="small" @click="backClick()"><template #icon><Back /></template>ш┐ФхЫЮ</el-button>
				</div>
			</div>
			<div class="admin-actions">
				<div class="action-left">
					<el-button class="btn-plain" size="small" @click="refreshClick()"><template #icon><RefreshRight /></template>хИ╖цЦ░</el-button>
					<el-button class="btn-danger" v-if="isAuth('discussjinengxuqiu','хИащЩд')" :disabled="dataListSelections.length?false:true" size="small" @click="deleteHandler()"><template #icon><Delete /></template>хИащЩд</el-button>
				</div>
			</div>
			<div class="admin-table-wrap">
				<el-table class="tables"
					:stripe='false'
					:border='false'
					:data="dataList"
					v-loading="dataListLoading"
					@selection-change="selectionChangeHandler">
					<el-table-column :resizable='true' type="selection" align="center" width="50"></el-table-column>
					<el-table-column :resizable='true' :sortable='true' label="х║ПхП╖" type="index" width="50" />
				<el-table-column :resizable='true' :sortable='true'
											prop="nickname"
					label="цШ╡чз░">
						<template #default="scope">
							{{scope.row.nickname}}
						</template>
					</el-table-column>
					<el-table-column :resizable='true' :sortable='true' prop="content" label="шпДшо║хЖЕхо╣">
						<template #default="scope">
							<span class="ql-snow ql-editor" v-html="scope.row.content"></span>
						</template>
					</el-table-column>
					<el-table-column :resizable='true' :sortable='true' prop="score" label="шпДхИЖ">
						<template #default="scope">
							<el-rate
								v-model="scope.row.score"
								:max="5"
								disabled
							/>
						</template>
					</el-table-column>
					<el-table-column :resizable='true' :sortable='true' prop="reply" label="хЫЮхдНхЖЕхо╣">
						<template #default="scope">
							<span class="ql-snow ql-editor" v-html="scope.row.reply"></span>
						</template>
					</el-table-column>
					<el-table-column :resizable='true' :sortable='true' prop="istop" label="цШпхРжч╜ощб╢">
						<template #default="scope">
							<el-switch
								v-model="scope.row.istop"
								:width="36"
								active-text="х╝А"
								inactive-text="хЕ│"
								:active-value="1"
								:inactive-value="0"
								style="--el-switch-on-color: #875F41; --el-switch-off-color: #ccc;"
								@change="(e)=>discussistopChange(e,scope.row)">
							</el-switch>
						</template>
					</el-table-column>
					<el-table-column width="300" label="цУНф╜Ь">
						<template #default="scope">
							<el-button v-if=" isAuth('discussjinengxuqiu','ф┐оцФ╣') " type="warning" plain size="small" @click="addOrUpdateHandler(scope.row.id)">ф┐оцФ╣</el-button>
							<el-button v-if="isAuth('discussjinengxuqiu','цЯечЬЛшпДшо║')" type="success" plain size="small" @click="disscussListHandler(scope.row.id)">цЯечЬЛшпДшо║</el-button>
							<el-button type="info" plain size="small" @click="addOrUpdateHandler(scope.row.id)">хЫЮхдН</el-button>
							<el-button v-if="isAuth('jinengxuqiu','хИащЩдшпДшо║')" type="danger" plain size="small" @click="deleteHandler(scope.row.id ,scope.row.refid)">хИащЩд</el-button>
						</template>
					</el-table-column>
				</el-table>
			</div>
			<div class="admin-pagination"><el-pagination
				@size-change="sizeChangeHandle"
				@current-change="currentChangeHandle"
				:current-page="pageIndex"
				background
				:page-size="pageSize"
				:layout="layouts.join()"
				:total="totalPage"
				prev-text="< "
				next-text="> "
				:hide-on-single-page="false"
			></el-pagination></div>
		</template>
		<!-- ц╖╗хКа/ф┐оцФ╣щб╡щЭв  х░ЖчИ╢ч╗Дф╗╢чЪДsearchцЦ╣ц│Хф╝ащАТч╗ЩхнРч╗Дф╗╢-->
		<add-or-update v-if="addOrUpdateFlag" :parent="this" ref="addOrUpdate"></add-or-update>





	</div>
</template>

<script>
	import AddOrUpdate from "./add-or-update.vue";
	export default {
		data() {
			return {
				indexQueryCondition: '',
				searchForm: {
					key: ""
				},
				form:{},
				dataList: [],
				pageIndex: 1,
				pageSize: 15,
				totalPage: 0,
				dataListLoading: false,
				dataListSelections: [],
				showFlag: true,
				addOrUpdateFlag:false,
				layouts: ["total","prev","pager","next","jumper"],
			};
		},
		created() {
			if(this.statType) {
				return false
			}
			this.init();
			this.getDataList();
		},
		mounted() {
		},
		watch: {
		},
		computed: {
			tablename(){
				return this.$storage.get('sessionTable')
			},
			role(){
				return this.$storage.get('role')
			},
		},
		components: {
			AddOrUpdate},
		methods: {
			refreshClick(){
				this.searchForm = {}
				this.search()
			},
			queryChange(arr){
				for(let x in arr) {
					if(arr[x] == this.role) {
						return true
					}
				}
				return false
			},
			init () {
			},
			search() {
				this.pageIndex = 1;
				this.getDataList();
			},

			// шО╖хПЦцХ░цНохИЧшби
			getDataList() {
				this.dataListLoading = true;
				let params = {
					page: this.pageIndex,
					limit: this.pageSize,
					sort: 'id',
					order: 'desc',
					refid : this.$route.query.refid,
				}
				let user = JSON.parse(this.$storage.getObj('userForm'))
				this.$http({
					url: "discussjinengxuqiu/page",
					method: "get",
					params: params
				}).then(({ data }) => {
					if (data && data.code === 0) {
						for(let x in data.data.list) {
							if(data.data.list[x].content) {
								data.data.list[x].content = data.data.list[x].content.replace(/img src/gi,"img style=\"width:100%;\" src");
							}
							if(data.data.list[x].reply) {
								data.data.list[x].reply = data.data.list[x].reply.replace(/img src/gi,"img style=\"width:100%;\" src");
							}
						}
						this.dataList = data.data.list;
						this.totalPage = data.data.total;
					} else {
						this.dataList = [];
						this.totalPage = 0;
					}
					this.dataListLoading = false;
				});
			},
			// цпПщб╡цХ░
			sizeChangeHandle(val) {
				this.pageSize = val;
				this.pageIndex = 1;
				this.getDataList();
			},
			// х╜УхЙНщб╡
			currentChangeHandle(val) {
				this.pageIndex = val;
				this.getDataList();
			},
			// хдЪщАЙ
			selectionChangeHandler(val) {
				this.dataListSelections = val;
			},
			// ц╖╗хКа/ф┐оцФ╣
			addOrUpdateHandler(id,type) {
				this.showFlag = false;
				this.addOrUpdateFlag = true;
				this.crossAddOrUpdateFlag = false;
				if(type!='info'&&type!='msg'){
					type = 'else';
				}
				this.$nextTick(() => {
					this.$refs.addOrUpdate.init(id,type );
				});
			},
			// цЯечЬЛшпДшо║
			disscussListHandler(id,type) {
				this.$router.push({path:'/discussjinengxuqiu',query:{refid:id}});
			},
			backClick(){
				history.back()
			},
			discussistopChange(e,row){
				this.$http({
					url:'discussjinengxuqiu/update',
					method:'post',
					data:row
				}).then(res=>{})
			},
			// хИащЩд
			async deleteHandler(id ,refid ) {
				var ids = id? [Number(id)]: this.dataListSelections.map(item => {
					return Number(item.id);
				});
				await this.$confirm(`чбохоЪш┐ЫшбМ[${id ? "хИащЩд" : "цЙ╣щЗПхИащЩд"}]цУНф╜Ь?`, "цПРчд║", {
					confirmButtonText: "чбохоЪ",
					cancelButtonText: "хПЦц╢И",
					type: "warning"
				}).then(async () => {
					await this.$http({
						url: "discussjinengxuqiu/delete",
						method: "post",
						data: ids
					}).then(async ({ data }) => {
						if (data && data.code === 0) {
							this.$http({
								url: 'jinengxuqiu/info/' + refid,
								method: "get",
							}).then(res=>{
								if(res.data&&res.data.code==0){
									res.data.data.discussnum = res.data.data.discussnum - Number(ids.length)
									this.$http({
										url: 'jinengxuqiu/update',
										method: "post",
										data:res.data.data
									}).then(res1=>{
										if(res1.data&&res1.data.code==0){
											this.$message({
												message: "цУНф╜ЬцИРхКЯ",
												type: "success",
												duration: 1500,
												onClose: () => {
													this.search();
												}
											});
										}
									})
								}
							})
			
						} else {
							this.$message.error(data.msg);
						}
					});
				});
			},


		}

	};
</script>
