<script>
	import timeMethod from '@/components/common/timeMethod.js'
	import {
		WebsocketMixin
	} from '@/mixins/WebsocketMixin'
	export default {
		mixins: [WebsocketMixin],
		components: {},
		data() {
			return {
				dialogVisible: false,
				ruleForm: {},
				user: null,
				recordList: [],
				recordVisible: false,
				chatVisible: false,
				nowfid: 0,
				nowfpic:'',
				nowname: '',
				chatList: [],
				chatForm: {
					content: ''
				},
				uploadUrl: this.$base.url + 'file/upload',
				// шпнщЯ│шБКхдйчЫ╕хЕ│
				isRecording: false,
				mediaRecorder: null,
				audioStream: null,
				audioChunks: [],
				recordDuration: 0,
				recordTimer: null,
				hasChatList: [
				],
				sensitiveWordsArr: [],
				topLogoUrl: '',
			};
		},
		created() {
			this.$http.get('config/info?name=bTopLogo',).then(rs=>{this.topLogoUrl = rs.data.data?rs.data.data.value:''})
			this.getSensitiveWords()
		},
		computed: {
			avatar(){
				return this.$storage.get('headportrait')?this.$storage.get('headportrait'):''
			},
			myid(){
				return this.$storage.get('userid')?this.$storage.get('userid'):''
			},
		},
		mounted() {
		},
		methods: {
			getSensitiveWords(){
				this.$http.get('sensitivewords/detail/1').then(rs=>{
					this.sensitiveWordsArr = rs.data.data.content.split(',')
				})
			},
			changeHasChat(){
				let table = this.$storage.get('sessionTable')
				for(let x in this.hasChatList){
					if(this.hasChatList[x]==table){
						return true
					}
				}
				return false
			},
			handleCommand(name) {
				if (name == 'logout') {
					this.onLogout()
				} 
				else if (name == 'front') {
					this.onIndexTap()
				}
				else if (name == 'backUp'){
					this.backUp()
				}
				else if (name == 'chat'){
					this.getRecordList()
				}
				else {
					let router = this.$router
					name = '/'+name
					router.push(name)
				}
			},
			getRecordList() {
				this.$http.get('friend/page2', {
					params: {
						uid: this.$storage.get('userid'),
						type: 2
					}
				}).then(res => {
					if (res.data && res.data.code == 0) {
						this.recordList = res.data.data.list
						this.recordVisible = true
					}
				})
			},
			chatClick(row) {
				this.nowfid = row.fid
				this.nowfpic = row.picture
				this.nowname = row.name
				this.initWebSocket(this.nowfid)
				this.getChatList()
				this.chatVisible = true
			},
			websocketOnopen: function() {
				
			},
			websocketOnmessage:function(e) {
				this.getChatList()
			},
			getChatList() {
				this.$http.get('chatmessage/mlist', {
					params: {
						page: 1,
						limit: 1000,
						uid: this.$storage.get('userid'),
						fid: this.nowfid
					}
				}).then(res => {
					if (res.data && res.data.code == 0) {
						this.chatList = this.formatMessages(res.data.data.list)
						let div = document.getElementsByClassName('chat-content')[0]
						setTimeout(() => {
							if (div)
								div.scrollTop = div.scrollHeight
						}, 0)
					}
				})
			},
			chatDel(row){
				this.$confirm('цШпхРжхИащЩдшБКхдйшо░х╜Хя╝Я').then(_ => {
					let arr = []
					let brr = []
					this.$http.get('chatmessage/list',{params: {
						page: 1,
						limit: 10000,
						uid: Number(this.$storage.get('userid')),
						fid: row.fid
					}}).then(rs=>{
						if(rs.data.data.list.length){
							for(let x in rs.data.data.list){
								arr.push(rs.data.data.list[x].id)
							}
						}
						this.$http.get('chatmessage/list',{params: {
							page: 1,
							limit: 10000,
							uid: row.fid,
							fid: Number(this.$storage.get('userid'))
						}}).then(rs2=>{
							if(rs2.data.data.list.length){
								for(let x in rs2.data.data.list){
									arr.push(rs2.data.data.list[x].id)
								}
							}
							this.$http.post('chatmessage/delete',arr).then(()=>{
								this.$http.get('friend/list',{params: {
									page: 1,
									limit: 10000,
									uid: Number(this.$storage.get('userid')),
									fid: row.fid,
									type: 0
								}}).then(rs3=>{
									if(rs3.data.data.list.length){
										for(let x in rs3.data.data.list){
											brr.push(rs3.data.data.list[x].id)
										}
									}
									this.$http.get('friend/list',{params: {
										page: 1,
										limit: 10000,
										uid: row.fid,
										fid: Number(this.$storage.get('userid')),
										type: 0
									}}).then(rs4=>{
										if(rs4.data.data.list.length){
											for(let x in rs4.data.data.list){
												brr.push(rs4.data.data.list[x].id)
											}
										}
										this.$http.get('friend/list',{params: {
											page: 1,
											limit: 10000,
											uid: Number(this.$storage.get('userid')),
											fid: row.fid,
											type: 2
										}}).then(rs5=>{
											if(rs5.data.data.list.length){
												for(let x in rs5.data.data.list){
													brr.push(rs5.data.data.list[x].id)
												}
											}
											this.$http.get('friend/list',{params: {
												page: 1,
												limit: 10000,
												uid: row.fid,
												fid: Number(this.$storage.get('userid')),
												type: 2
											}}).then(rs6=>{
												if(rs6.data.data.list.length){
													for(let x in rs6.data.data.list){
														brr.push(rs6.data.data.list[x].id)
													}
												}
												this.$http.post('friend/delete',brr).then(()=>{
													this.$message.success('хИащЩдцИРхКЯ')
													this.getRecordList()
												})
											})
										})
									})
								})
							})
						})
					})
				}).catch(_ => {});
			},
			formatMessages(messages) {
				let lastTime = null;
				messages.forEach((message, index) => {
					const currentTime = new Date(message.addtime).getTime();
					if (lastTime !== null) {
						const timeDiff = (currentTime - lastTime) / 1000 / 60; // ш╜мцНвф╕║хИЖщТЯ
						if (timeDiff < 3) {
							message.addtime = ''; // хжВцЮЬх░Пф║О3хИЖщТЯя╝Мф╕НцШ╛чд║цЧ╢щЧ┤
						}
					}
					lastTime = currentTime;
				});
				return messages;
			},
			timeFormat(time) {
				const Time = timeMethod.getTime(time).split("T");
				//х╜УхЙНц╢ИцБпцЧецЬЯх▒Юф║ОхСи
				const week = timeMethod.getDateToWeek(time);
				//х╜УхЙНцЧецЬЯ0цЧ╢
				const nti = timeMethod.setTimeZero(timeMethod.getNowTime());
				//ц╢ИцБпцЧецЬЯх╜Ухдй0цЧ╢
				const mnti = timeMethod.setTimeZero(timeMethod.getTime(time));
				//шобчоЧцЧецЬЯх╖охА╝
				const diffDate = timeMethod.calculateTime(nti, mnti);
				//цЬмхСиф╕АцЧецЬЯ0цЧ╢ я╝ИхРОщЭв+1цШпхО╗щЩдх╜УхдйцЧ╢щЧ┤я╝Й
				const fwnti = timeMethod.setTimeZero(timeMethod.countDateStr(-timeMethod.getDateToWeek(timeMethod
					.getNowTime()).weekID + 1));
				//шобчоЧхСицЧецЬЯх╖охА╝
				const diffWeek = timeMethod.calculateTime(mnti, fwnti);

				if (diffDate === 0) { //ц╢ИцБпхПСщАБцЧецЬЯхЗПхО╗х╜УхдйцЧецЬЯхжВцЮЬчнЙф║О0хИЩцШпх╜УхдйцЧ╢щЧ┤
					return Time[1].slice(0, 5);
				} else if (diffDate < 172800000) { //х╜УхЙНцЧецЬЯхЗПхО╗ц╢ИцБпхПСщАБцЧецЬЯх░Пф║О2хдйя╝И172800000msя╝ЙхИЩцШпцШихдй-  ф╕АхдйцЬАхдзх╖охА╝хЙНхдйхЗМцЩи00:00:00хИ░ф╗КхдйцЩЪф╕К23:59:59
					return "цШихдй " + Time[1].slice(0, 5);
				} else if (diffWeek >= 0) { //ц╢ИцБпцЧецЬЯхЗПхО╗цЬмхСиф╕АцЧецЬЯхдзф║О0хИЩцШпцЬмхСи
					return week.weekName;
				} else { //хЕ╢ф╗ЦцЧ╢щЧ┤хИЩцШпцЧецЬЯ
					return Time[0].slice(5, 10);
				}
			},
			clearChat(){
				this.websocketOnclose();
				this.chatList = []
				this.getRecordList()
			},
			// хИЗцНвх╜ХщЯ│чК╢цАБя╝ИчВ╣хЗ╗х╝АхзЛ/хБЬцнвя╝Й
			toggleRecord() {
				if (this.isRecording) {
					// хжВцЮЬцнгхЬих╜ХщЯ│я╝МхИЩхБЬцнв
					this.stopRecord()
				} else {
					// хжВцЮЬцЬкх╜ХщЯ│я╝МхИЩх╝АхзЛ
					this.startRecord()
				}
			},
			// х╝АхзЛх╜ХщЯ│
			async startRecord() {
				if (this.isRecording) return
				
				try {
					// шп╖ц▒Вщ║жхЕЛщгОцЭГщЩР
					this.audioStream = await navigator.mediaDevices.getUserMedia({ audio: true })
					
					// цгАцЯец╡ПшзИхЩицШпхРжцФпцМБ MediaRecorder
					if (!window.MediaRecorder) {
						this.$message.error('цВичЪДц╡ПшзИхЩиф╕НцФпцМБх╜ХщЯ│хКЯшГ╜')
						return
					}
					
					// шО╖хПЦцФпцМБчЪД MIME ч▒╗хЮЛ
					let mimeType = 'audio/webm'
					if (!MediaRecorder.isTypeSupported('audio/webm')) {
						if (MediaRecorder.isTypeSupported('audio/mp4')) {
							mimeType = 'audio/mp4'
						} else if (MediaRecorder.isTypeSupported('audio/ogg')) {
							mimeType = 'audio/ogg'
						} else {
							mimeType = '' // ф╜┐чФиц╡ПшзИхЩищ╗Шшодца╝х╝П
						}
					}
					
					// хИЭхзЛхМЦх╜ХщЯ│хЩи
					const options = mimeType ? { mimeType: mimeType } : {}
					this.mediaRecorder = new MediaRecorder(this.audioStream, options)
					this.audioChunks = []
					
					// чЫСхРмцХ░цНохПпчФиф║Лф╗╢я╝ИцпП100msцФ╢щЫЖф╕АцмбцХ░цНоя╝Й
					this.mediaRecorder.ondataavailable = (event) => {
						if (event.data && event.data.size > 0) {
							this.audioChunks.push(event.data)
						}
					}
					
					// чЫСхРмх╜ХщЯ│хБЬцнвф║Лф╗╢
					this.mediaRecorder.onstop = () => {
						// хБЬцнвцЙАцЬЙщЯ│щвСш╜ищБУ
						if (this.audioStream) {
							this.audioStream.getTracks().forEach(track => track.stop())
							this.audioStream = null
						}
					}
					
					// чЫСхРмщФЩшппф║Лф╗╢
					this.mediaRecorder.onerror = (event) => {
						console.error('х╜ХщЯ│щФЩшпп:', event.error)
						this.$message.error('х╜ХщЯ│ш┐ЗчиЛф╕нхПСчФЯщФЩшпп')
						this.stopRecord()
					}
					
					// х╝АхзЛх╜ХщЯ│я╝МцпП100msцФ╢щЫЖф╕АцмбцХ░цНо
					this.mediaRecorder.start(100)
					this.isRecording = true
					this.recordDuration = 0
					
					// х╝АхзЛшобцЧ╢
					this.recordTimer = setInterval(() => {
						this.recordDuration++
						// цЬАщХ┐х╜ХщЯ│60чзТ
						if (this.recordDuration >= 60) {
							this.stopRecord()
							this.$message.info('х╜ХщЯ│х╖▓ш╛╛хИ░цЬАхдзцЧ╢щХ┐я╝Мх╖▓шЗкхКихБЬцнв')
						}
					}, 1000)
					
				} catch (error) {
					console.error('цЧац│Хшо┐щЧощ║жхЕЛщгО:', error)
					this.isRecording = false
					if (error.name === 'NotAllowedError' || error.name === 'PermissionDeniedError') {
						this.$message.error('щ║жхЕЛщгОцЭГщЩРшвлцЛТч╗Эя╝Мшп╖хЬиц╡ПшзИхЩишо╛ч╜оф╕нхЕБшо╕шо┐щЧощ║жхЕЛщгО')
					} else if (error.name === 'NotFoundError' || error.name === 'DevicesNotFoundError') {
						this.$message.error('цЬкцгАц╡ЛхИ░щ║жхЕЛщгОшо╛хдЗ')
					} else {
						this.$message.error('цЧац│Хшо┐щЧощ║жхЕЛщгОя╝Мшп╖цгАцЯецЭГщЩРшо╛ч╜о')
					}
				}
			},
			// хБЬцнвх╜ХщЯ│
			stopRecord() {
				if (!this.isRecording) return
				
				// ц╕ЕщЩдшобцЧ╢хЩи
				if (this.recordTimer) {
					clearInterval(this.recordTimer)
					this.recordTimer = null
				}
				
				// хБЬцнвх╜ХщЯ│
				if (this.mediaRecorder && this.mediaRecorder.state !== 'inactive') {
					try {
						this.mediaRecorder.stop()
					} catch (e) {
						console.error('хБЬцнвх╜ХщЯ│хд▒ш┤е:', e)
					}
				}
				
				this.isRecording = false
				
				// хжВцЮЬх╜ХщЯ│цЧ╢щХ┐хдкчЯня╝Мф╕НхПСщАБ
				if (this.recordDuration < 1) {
					this.$message.warning('х╜ХщЯ│цЧ╢щЧ┤хдкчЯня╝Мшп╖шЗ│х░Сх╜ХщЯ│1чзТ')
					this.recordDuration = 0
					this.audioChunks = []
					return
				}
				
				// чнЙх╛Ех╜ХщЯ│цХ░цНоцФ╢щЫЖхоМцИР
				setTimeout(() => {
					this.uploadAudio()
				}, 200)
			},
			// ф╕Кф╝ах╜ХщЯ│
			uploadAudio() {
				if (this.audioChunks.length === 0) {
					this.$message.error('х╜ХщЯ│цХ░цНоф╕║чй║')
					return
				}
				
				// чбохоЪцЦЗф╗╢цЙйх▒ХхРН
				let fileExtension = 'webm'
				let mimeType = 'audio/webm'
				if (this.mediaRecorder && this.mediaRecorder.mimeType) {
					mimeType = this.mediaRecorder.mimeType
					if (mimeType.includes('mp4')) {
						fileExtension = 'mp4'
					} else if (mimeType.includes('ogg')) {
						fileExtension = 'ogg'
					} else if (mimeType.includes('wav')) {
						fileExtension = 'wav'
					}
				}
				
				// хРИх╣╢щЯ│щвСцХ░цНо
				const audioBlob = new Blob(this.audioChunks, { type: mimeType })
				
				// цгАцЯецЦЗф╗╢хдзх░Пя╝ИщЩРхИ╢ф╕║10MBя╝Й
				if (audioBlob.size > 10 * 1024 * 1024) {
					this.$message.error('х╜ХщЯ│цЦЗф╗╢ш┐Зхдзя╝Мшп╖ч╝йчЯнх╜ХщЯ│цЧ╢щЧ┤')
					this.audioChunks = []
					this.recordDuration = 0
					return
				}
				
				// хИЫх╗║FormDataф╕Кф╝а
				const formData = new FormData()
				formData.append('file', audioBlob, `voice_${Date.now()}.${fileExtension}`)
				
				// цШ╛чд║ф╕Кф╝ацПРчд║
				const loading = this.$loading({
					lock: true,
					text: 'цнгхЬиф╕Кф╝ашпнщЯ│...',
					background: 'rgba(0, 0, 0, 0.7)'
				})
				
				// ф╕Кф╝ацЦЗф╗╢
				this.$http.post(this.uploadUrl, formData, {
					headers: {
						'Content-Type': 'multipart/form-data'
					}
				}).then(res => {
					loading.close()
					if (res.data && res.data.code == 0) {
						// ф╕Кф╝ацИРхКЯя╝МхПСщАБшпнщЯ│ц╢ИцБп
						this.addChat('upload/' + res.data.file, 5)
						this.$message.success('шпнщЯ│хПСщАБцИРхКЯ')
					} else {
						this.$message.error(res.data.msg || 'ф╕Кф╝ахд▒ш┤е')
					}
				}).catch(error => {
					loading.close()
					console.error('ф╕Кф╝ахд▒ш┤е:', error)
					this.$message.error('шпнщЯ│ф╕Кф╝ахд▒ш┤ея╝Мшп╖щЗНшпХ')
				}).finally(() => {
					// щЗНч╜очК╢цАБ
					this.audioChunks = []
					this.recordDuration = 0
					this.mediaRecorder = null
				})
			},
			uploadSuccess(res) {
				if (res.code == 0) {
					this.addChat('upload/' + res.file,2);
				}
			},
			uploadSuccess2(res) {
				if (res.code == 0) {
					this.addChat('upload/' + res.file,3);
				}
			},
			uploadSuccess3(res) {
				if (res.code == 0) {
					this.addChat('upload/' + res.file,4);
				}
			},
			addChat(ask=null,type=1) {
				if(!ask) {
					for(var i=0; i<this.sensitiveWordsArr.length; i++){
						//хЕих▒АцЫ┐цНв
						var reg = new RegExp(this.sensitiveWordsArr[i],"g");
						//хИдцЦнхЖЕхо╣ф╕нцШпхРжхМЕцЛмцХПцДЯшпН
						if (this.chatForm.content.indexOf(this.sensitiveWordsArr[i]) > -1) {
							// х░ЖцХПцДЯшпНцЫ┐цНвф╕║ **
							this.chatForm.content = this.chatForm.content.replace(reg,"**");
						}
					}
				}
				this.$http.post('chatmessage/add', {
					uid: this.$storage.get('userid'),
					fid: this.nowfid,
					content: ask?ask:this.chatForm.content,
					format: type
				}).then(res2 => {
					this.websocketSend(ask?ask:this.chatForm.content)
					this.chatForm = {
						content: ''
					}
					this.getChatList()
				})
			},
			// щвДшзИ
			download(file){
				if(!file){
					return false
				}
				window.open((location.href.split(this.$base.name).length>1 ? location.href.split(this.$base.name)[0] + this.$base.name + '/' + file :this.$base.url + file))
			},
			async onLogout() {
				await this.$http.post(`${this.$storage.get('sessionTable')}/logout`).then(rs=>{
					this.$storage.clear()
					this.$store.dispatch('tagsView/delAllViews')
					window.location.href = this.$base.indexUrl
				})
			},
			onIndexTap(){
				localStorage.setItem("frontToken", localStorage.getItem("Token"));
				localStorage.setItem("frontRole", localStorage.getItem("role"));
				localStorage.setItem("frontSessionTable", localStorage.getItem("sessionTable"));
				localStorage.setItem("frontHeadportrait", localStorage.getItem("headportrait"));
				localStorage.setItem("UserTableName", localStorage.getItem("sessionTable"));
				localStorage.setItem("frontUserid", localStorage.getItem("userid"));
				localStorage.setItem("username", localStorage.getItem("adminName"));
				window.location.href = `${this.$base.indexUrl}`
			},
			backUp() {
				this.$confirm('цШпхРжхдЗф╗╜цХ░цНох║У?', 'цХ░цНохдЗф╗╜цПРчд║', {
					confirmButtonText: 'цШп',
					cancelButtonText: 'хРж',
					type: 'warning'
				}).then(() => {
					this.$http({
						url: '/mysqldump',
						method: "get"
					}).then(({
						data
					}) => {
						if (data) {
							const binaryData = [];
							binaryData.push(data);
							const objectUrl = window.URL.createObjectURL(new Blob(binaryData, {
								type: 'application/pdf;chartset=UTF-8'
							}))
							const a = document.createElement('a')
							a.href = objectUrl
							a.download = 'mysql.dmp'
							// a.click()
							// ф╕ЛщЭвш┐Щф╕кхЖЩц│ХхЕ╝хо╣чБлчЛР
							a.dispatchEvent(new MouseEvent('click', {
								bubbles: true,
								cancelable: true,
								view: window
							}))
							window.URL.revokeObjectURL(objectUrl)
							this.$message.success('цХ░цНохдЗф╗╜цИРхКЯ')
						} else {
							this.$message.error(data && data.msg ? data.msg : 'хдЗф╗╜хд▒ш┤е');
						}
					});
				});
			},
		}
	};
</script>


