  
<template>
	<div class="main-content" style="min-height:100%;width:100%;padding:0;background:none;">
		<!-- хИЧшбищб╡ -->
		<template v-if="showFlag ">
			<div class="admin-search">
				<div class="search-field">
					<span class="field-label">чФицИ╖</span>
					<el-input v-model="searchForm.yonghuxingming" placeholder="чФицИ╖хзУхРН" @keydown.enter="search()" clearable size="small"></el-input>
				</div>
				<div class="search-actions">
					<el-button class="btn-primary" size="small" icon="el-icon-search" @click="search()">цЯешпв</el-button>
					<el-button class="btn-plain" size="small" icon="el-icon-refresh" @click="searchForm={ key: '' }; search()">щЗНч╜о</el-button>
				</div>
			</div>
			<div class="admin-table-wrap">
				<el-table class="tables"
					:stripe='false'
					:border='false'
					v-if="isAuth('huiyuanchongzhi','цЯечЬЛ')"
					:data="dataList"
					v-loading="dataListLoading">
					<el-table-column :resizable='true' :sortable='true' label="х║ПхП╖" type="index" width="60" />
				<el-table-column :resizable='true' :sortable='true'
											prop="yonghuxingming"
					label="чФицИ╖" min-width="100">
					<template #default="scope">
						{{scope.row.yonghuxingming}}
					</template>
				</el-table-column>
				<el-table-column :resizable='true' :sortable='true'
											prop="taocan"
					label="хеЧщдР" min-width="120">
					<template #default="scope">
						{{scope.row.taocan || '-'}}
					</template>
				</el-table-column>
				<el-table-column :resizable='true' :sortable='true'
											prop="chongzhijine"
					label="хЕЕхА╝щЗСщвЭ" min-width="100">
					<template #default="scope">
						<span style="color:#e74c3c;font-weight:bold;">┬е{{scope.row.chongzhijine}}</span>
					</template>
				</el-table-column>
				<el-table-column :resizable='true' :sortable='true'
											prop="zhifufangshi"
					label="цФпф╗ШцЦ╣х╝П" min-width="100">
					<template #default="scope">
						{{scope.row.zhifufangshi || '-'}}
					</template>
				</el-table-column>
				<el-table-column :resizable='true' :sortable='true'
											prop="zhuangtai"
					label="чК╢цАБ" min-width="90">
					<template #default="scope">
				<span class="status-badge status-paid" v-if="scope.row.zhuangtai=='х╖▓цФпф╗Ш'">х╖▓цФпф╗Ш</span>
				<span class="status-badge status-pending" v-else-if="scope.row.zhuangtai=='х╛ЕцФпф╗Ш'">х╛ЕцФпф╗Ш</span>
				<span class="status-badge status-cancelled" v-else-if="scope.row.zhuangtai=='х╖▓хПЦц╢И'">х╖▓хПЦц╢И</span>
				<span class="status-badge status-default" v-else>{{scope.row.zhuangtai || '-'}}</span>
					</template>
				</el-table-column>
				<el-table-column :resizable='true' :sortable='true'
											prop="chongzhiriqi"
					label="хЕЕхА╝цЧецЬЯ" min-width="110">
					<template #default="scope">
						{{scope.row.chongzhiriqi}}
					</template>
				</el-table-column>
				</el-table>
			</div>
			<div class="admin-pagination">
				<el-pagination
					@size-change="sizeChangeHandle"
					@current-change="currentChangeHandle"
					:current-page="pageIndex"
					background

					:page-size="pageSize"
					:layout="layouts.join()"
					:total="totalPage"
					prev-text="< "
					next-text="> "
					:hide-on-single-page="false"
				></el-pagination>
			</div>
		</template>
		<!-- ц╖╗хКа/ф┐оцФ╣щб╡щЭв  х░ЖчИ╢ч╗Дф╗╢чЪДsearchцЦ╣ц│Хф╝ащАТч╗ЩхнРч╗Дф╗╢-->
		<add-or-update v-if="addOrUpdateFlag" :parent="this" ref="addOrUpdate"></add-or-update>





		<el-dialog title="щвДшзИхЫ╛" :visible.sync="previewVisible" width="480px" :close-on-click-modal="false">
			<img :src="previewImg" alt="" style="width: 100%;">
		</el-dialog>
	</div>
</template>

<script>
	import * as echarts from 'echarts'
	import chinaJson from "@/components/echarts/china.json";
	import axios from 'axios';
	import AddOrUpdate from "./add-or-update.vue";
	export default {
		components: {
			AddOrUpdate},
		data() {
			return {
				indexQueryCondition: '',
				searchForm: {
					key: ""
				},
				form:{},
				dataList: [],
				pageIndex: 1,
				pageSize: 15,
				totalPage: 0,
				dataListLoading: false,
				dataListSelections: [],
				showFlag: true,
				addOrUpdateFlag:false,
				layouts: ["total","prev","pager","next","jumper"],
				previewImg: '',
				previewVisible: false,
			};
		},
		created() {
			if(this.statType) {
				return false
			}
			this.init();
			this.getDataList();
		},
		mounted() {
		},
		watch: {
		},
		computed: {
			tablename(){
				return this.$storage.get('sessionTable')
			},
			role(){
				return this.$storage.get('role')
			},
			statType() {
				return this.$route.path.endsWith('stat')
			}
		},
		methods: {
			queryChange(arr){
				for(let x in arr) {
					if(arr[x] == this.role) {
						return true
					}
				}
				return false
			},
			imgPreView(url){
				this.previewImg = url
				this.previewVisible = true
				
			},
			init () {
			},
			search() {
				this.pageIndex = 1;
				this.getDataList();
			},

			// шО╖хПЦцХ░цНохИЧшби
			getDataList() {
				this.dataListLoading = true;
				let params = {
					page: this.pageIndex,
					limit: this.pageSize,
					sort: 'id',
					order: 'desc',
				}
				if(this.searchForm.yonghuxingming!='' && this.searchForm.yonghuxingming!=undefined){
					params['yonghuxingming'] = '%' + this.searchForm.yonghuxingming + '%'
				}
				let user = JSON.parse(this.$storage.getObj('userForm'))
				this.$http({
					url: "huiyuanchongzhi/page",
					method: "get",
					params: params
				}).then(({ data }) => {
					if (data && data.code === 0) {
						this.dataList = data.data.list;
						this.totalPage = data.data.total;
					} else {
						this.dataList = [];
						this.totalPage = 0;
					}
					this.dataListLoading = false;
				});
			},
			// цпПщб╡цХ░
			sizeChangeHandle(val) {
				this.pageSize = val;
				this.pageIndex = 1;
				this.getDataList();
			},
			// х╜УхЙНщб╡
			currentChangeHandle(val) {
				this.pageIndex = val;
				this.getDataList();
			},
			// хдЪщАЙ
			selectionChangeHandler(val) {
				this.dataListSelections = val;
			},
			// ц╖╗хКа/ф┐оцФ╣
			addOrUpdateHandler(id,type) {
				this.showFlag = false;
				this.addOrUpdateFlag = true;
				this.crossAddOrUpdateFlag = false;
				if(type!='info'&&type!='msg'){
					type = 'else';
				}
				this.$nextTick(() => {
					this.$refs.addOrUpdate.init(id,type );
				});
			},
			// хИащЩд
			async deleteHandler(id ) {
				var ids = id? [Number(id)]: this.dataListSelections.map(item => {
					return Number(item.id);
				});
				await this.$confirm(`чбохоЪш┐ЫшбМ[${id ? "хИащЩд" : "цЙ╣щЗПхИащЩд"}]цУНф╜Ь?`, "цПРчд║", {
					confirmButtonText: "чбохоЪ",
					cancelButtonText: "хПЦц╢И",
					type: "warning"
				}).then(async () => {
					await this.$http({
						url: "huiyuanchongzhi/delete",
						method: "post",
						data: ids
					}).then(async ({ data }) => {
						if (data && data.code === 0) {
							this.$message({
								message: "цУНф╜ЬцИРхКЯ",
								type: "success",
								duration: 1500,
								onClose: () => {
									this.search();
								}
							});
			
						} else {
							this.$message.error(data.msg);
						}
					});
				});
			},


		}

	};
</script>
